import {
  type ReactElement,
  type ReactNode,
  type RefObject,
  useEffect,
  useId,
  useRef,
} from "react";

import { type AccessibleText } from "../../lib/a11y-types";
import { withErrorOverlay } from "../../lib/dev-overlay";

import "./dialog.css";

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

// ---------------------------------------------------------------------------
// Props — discriminated union: exactly one label source required
// ---------------------------------------------------------------------------

type DialogLabelProps =
  | { title: AccessibleText; "aria-labelledby"?: never }
  | { title?: never; "aria-labelledby": string };

type DialogBaseProps = {
  open: boolean;
  onClose: () => void;
  children: ReactNode;
  description?: AccessibleText;
  initialFocusRef?: RefObject<HTMLElement | null>;
  returnFocusRef?: RefObject<HTMLElement | null>;
  /** Whether clicking the backdrop calls onClose. Defaults to true. */
  closeOnBackdropClick?: boolean;
  className?: string;
};

export type DialogProps = DialogBaseProps & DialogLabelProps;

// ---------------------------------------------------------------------------
// Module constants & pure helpers
// ---------------------------------------------------------------------------

const FOCUSABLE =
  'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';

function getFirstFocusable(container: HTMLElement): HTMLElement | null {
  // Prefer a focusable element inside the body slot over the header close button,
  // so keyboard users land on the dialog's primary content first.
  const body = container.querySelector<HTMLElement>(".artui-dialog-body");
  const bodyFirst = body?.querySelector<HTMLElement>(FOCUSABLE);
  if (bodyFirst) return bodyFirst;
  return container.querySelector<HTMLElement>(FOCUSABLE);
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function Dialog(props: DialogProps): ReactElement {
  // Props
  const {
    open,
    onClose,
    children,
    description,
    initialFocusRef,
    returnFocusRef,
    closeOnBackdropClick = true,
    className,
    ...labelRest
  } = props;

  // IDs
  const uid = useId();
  const titleId = `${uid}-title`;
  const descId = `${uid}-desc`;

  // Refs
  const dialogRef = useRef<HTMLDialogElement>(null);
  // Capture the element that had focus before the dialog opened so we can restore it.
  const returnTargetRef = useRef<Element | null>(null);

  // Computed
  const { title, "aria-labelledby": ariaLabelledBy } = labelRest as {
    title?: string;
    "aria-labelledby"?: string;
  };
  const hasChildren =
    children !== null && children !== undefined && children !== false;
  const labelledBy = title ? titleId : (ariaLabelledBy ?? titleId);

  // -------------------------------------------------------------------------
  // Lifecycle
  // -------------------------------------------------------------------------

  // Effect A — open transition: showModal, initial focus, event wiring.
  // Cleanup only removes listeners. dialog.close() is deliberately NOT called
  // here because this effect's cleanup fires after React has already committed
  // the re-render — by that point the <dialog> could have been removed from
  // the DOM (in a conditional-render pattern), making close() a no-op and
  // leaving NVDA's virtual buffer stranded in modal mode. close() is handled
  // exclusively by Effect B, which runs while the element is still mounted.
  useEffect(() => {
    if (!open) return;

    const dialog = dialogRef.current;
    if (!dialog) return;

    // Capture return-focus target before showModal moves focus.
    returnTargetRef.current =
      returnFocusRef?.current ?? document.activeElement;

    if (!dialog.open) {
      dialog.showModal();
    }

    // Move focus to initialFocusRef, or fall back to first focusable child.
    const focusTarget =
      initialFocusRef?.current ?? getFirstFocusable(dialog);
    if (focusTarget) {
      focusTarget.focus();
    }

    // Backdrop click: native <dialog> dispatches click on itself when the
    // user clicks the ::backdrop pseudo-element. Children stop bubbling.
    const handleClick = (e: MouseEvent) => {
      if (closeOnBackdropClick && e.target === dialog) {
        onClose();
      }
    };
    // Intercept native cancel (Escape) so we control the close sequence.
    const handleCancel = (e: Event) => {
      e.preventDefault();
      onClose();
    };
    dialog.addEventListener("click", handleClick);
    dialog.addEventListener("cancel", handleCancel);

    return () => {
      dialog.removeEventListener("click", handleClick);
      dialog.removeEventListener("cancel", handleCancel);
    };
  }, [open, initialFocusRef, returnFocusRef, onClose, closeOnBackdropClick]);

  // Effect B — close transition: dialog.close() then focus restore.
  // Running close() here (while the element is still in the DOM) ensures the
  // browser receives the close signal before any potential unmount, preventing
  // NVDA from getting stuck in a modal context with no dialog to read.
  useEffect(() => {
    if (open) return;
    const dialog = dialogRef.current;
    if (dialog?.open) {
      dialog.close();
    }
    const target = returnFocusRef?.current ?? returnTargetRef.current;
    if (target instanceof HTMLElement) {
      target.focus();
    }
  }, [open, returnFocusRef]);

  // Lock body scroll while open. Native <dialog> + showModal() does not prevent
  // background scrolling on its own (WCAG 2.4.11 — focused element not obscured).
  useEffect(() => {
    if (!open || typeof document === "undefined") return;
    const body = document.body;
    const previousOverflow = body.style.overflow;
    body.style.overflow = "hidden";
    return () => {
      body.style.overflow = previousOverflow;
    };
  }, [open]);

  // Runtime violation detection (dev overlays).
  useEffect(() => {
    if (!isDev || !open || !dialogRef.current) return;
    const dialog = dialogRef.current;

    // Dialog:labelledby-missing (4.1.2) — aria-labelledby points at a nonexistent element.
    if (ariaLabelledBy) {
      const target = document.getElementById(ariaLabelledBy);
      if (!target) {
        console.error(
          `[artui] <Dialog> [WCAG 4.1.2]: aria-labelledby="${ariaLabelledBy}" does not resolve to any element in the DOM.`,
        );
      }
    }

    // Dialog:no-focusable (2.1.1) — no focusable elements in the dialog body.
    // We check only the body slot, not the header close button.
    const body = dialog.querySelector(".artui-dialog-body");
    const bodyFocusable = body ? body.querySelectorAll(FOCUSABLE) : [];
    if (bodyFocusable.length === 0) {
      console.error(
        `[artui] <Dialog> [WCAG 2.1.1]: No focusable elements found inside the dialog body. Add at least one interactive element so keyboard users can act on the dialog.`,
      );
    }
  }, [open, ariaLabelledBy]);

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  // Always render the <dialog> element — never conditionally unmount it.
  // A closed native <dialog> (no `open` attribute) is display:none per the
  // browser UA stylesheet and invisible to the accessibility tree, so there
  // is no observable difference for users. Keeping it mounted ensures
  // dialog.close() can always be called before the element leaves the DOM,
  // which is required to correctly end the browser's top-layer modal session
  // and allow screen readers (NVDA, JAWS) to restore their virtual buffers.
  const element = (
    <dialog
      ref={dialogRef}
      aria-modal="true"
      aria-labelledby={labelledBy}
      aria-describedby={description ? descId : undefined}
      className={["artui-dialog", className].filter(Boolean).join(" ")}
    >
      <div className="artui-dialog-header">
        {title && (
          <h2 id={titleId} className="artui-dialog-title">
            {title}
          </h2>
        )}

        <button
          type="button"
          className="artui-dialog-close"
          aria-label="Close"
          onClick={onClose}
        >
          <svg
            aria-hidden="true"
            focusable="false"
            width="20"
            height="20"
            viewBox="0 0 20 20"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <line x1="4" y1="4" x2="16" y2="16" />
            <line x1="16" y1="4" x2="4" y2="16" />
          </svg>
        </button>
      </div>

      {description && (
        <p id={descId} className="artui-dialog-description">
          {description}
        </p>
      )}

      <div className="artui-dialog-body">{children}</div>
    </dialog>
  );

  // Dialog:empty-children (1.3.1) — only meaningful when the dialog is open.
  if (open && !hasChildren) {
    return withErrorOverlay(element, {
      key: "Dialog:empty-children",
      component: "Dialog",
      wcag: "1.3.1",
      message:
        "Dialog rendered with no children. Dialogs must contain content so screen reader users know what the dialog is about.",
    });
  }

  return element;
}

:root {
  --artui-dialog-bg: Canvas;
  --artui-dialog-color: CanvasText;
  --artui-dialog-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  --artui-dialog-width: auto;
  --artui-dialog-max-width: min(520px, calc(100vw - 32px));
  --artui-dialog-backdrop-bg: rgba(0, 0, 0, 0.45);
  --artui-dialog-backdrop-filter: blur(4px);
  --artui-dialog-focus-outline: 2px solid currentColor;
  --artui-dialog-focus-outline-offset: 2px;
}

.artui-dialog {
  position: fixed;
  inset: 0;
  margin: auto;
  width: var(--artui-dialog-width);
  height: fit-content;
  min-width: min(320px, calc(100vw - 32px));
  max-width: var(--artui-dialog-max-width);
  max-height: calc(100vh - 32px);
  padding: 24px;
  overflow-y: auto;
  background: var(--artui-dialog-bg);
  color: var(--artui-dialog-color);
  border: 1px solid color-mix(in srgb, currentColor 15%, transparent);
  border-radius: 12px;
  box-shadow: var(--artui-dialog-shadow);
  font-family: inherit;
  font-size: inherit;

  &::backdrop {
    background: var(--artui-dialog-backdrop-bg);
    backdrop-filter: var(--artui-dialog-backdrop-filter);
    -webkit-backdrop-filter: var(--artui-dialog-backdrop-filter);
  }

  & .artui-dialog-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 16px;
    margin-block-end: 16px;

    &:has(+ .artui-dialog-description) {
      margin-block-end: 4px;
    }
  }

  & .artui-dialog-title {
    flex: 1;
    margin: 0;
    font-size: 1.125em;
    font-weight: 600;
    line-height: 1.3;
  }

  & .artui-dialog-close {
    flex-shrink: 0;
    margin-inline-start: auto;
    inline-size: 44px;
    block-size: 44px;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    background: transparent;
    color: inherit;
    border: none;
    border-radius: 4px;
    cursor: pointer;

    &:focus {
      outline: var(--artui-dialog-focus-outline);
      outline-offset: var(--artui-dialog-focus-outline-offset);
    }

    &:hover {
      background: color-mix(in srgb, currentColor 8%, transparent);
    }
  }

  & .artui-dialog-description {
    margin-block: 0 16px;
    font-size: 0.9em;
    opacity: 0.75;
  }
}

@media (prefers-reduced-motion: no-preference) {
  .artui-dialog {
    animation: artui-dialog-in 180ms ease-out;
  }
}

@keyframes artui-dialog-in {
  from {
    opacity: 0;
    transform: translateY(-8px) scale(0.97);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

import type { ReactElement } from "react";

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

const reported = new Set<string>();

interface DevOverlayOptions {
  /** Stable key for de-duplicating the console.error call. */
  key: string;
  /** Component name shown in the error prefix, e.g. "Image". */
  component: string;
  /** Optional WCAG criterion, e.g. "1.1.1". */
  wcag?: string;
  /** Human-readable description of what went wrong. */
  message: string;
}

/**
 * Wraps `element` in a red full-coverage overlay and emits a console.error.
 *
 * No-op in production. In development, logs once per `key` then returns the
 * element wrapped in a positioned <span> with a red overlay on top.
 * The overlay uses aria-hidden and pointerEvents:none so it does not affect
 * the accessibility tree or interaction.
 */
export function withErrorOverlay(
  element: ReactElement,
  { key, component, wcag, message }: DevOverlayOptions,
): ReactElement {
  if (!isDev) return element;

  if (!reported.has(key)) {
    reported.add(key);
    const wcagSuffix = wcag ? ` [WCAG ${wcag}]` : "";
    console.error(`[artui] <${component}>${wcagSuffix}: ${message}`);
  }

  return (
    <span style={{ position: "relative", display: "inline-block" }}>
      {element}
      <span
        aria-hidden="true"
        style={{
          position: "absolute",
          inset: 0,
          background: "#d62828",
          pointerEvents: "none",
        }}
      />
    </span>
  );
}

/** Reset the de-duplication cache. Test-only. */
export function __resetDevOverlayCache(): void {
  reported.clear();
}

import {
  type KeyboardEvent,
  type ReactElement,
  type ReactNode,
  createContext,
  useCallback,
  useContext,
  useEffect,
  useId,
  useRef,
  useState,
} from "react";

import { type AccessibleNameProps } from "../../lib/a11y-types";
import { withErrorOverlay } from "../../lib/dev-overlay";

import "./dropdown-menu.css";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type Rect = { top: number; left: number; width: number; height: number };

// ---------------------------------------------------------------------------
// Root context
// ---------------------------------------------------------------------------

interface RootCtx {
  open: boolean;
  setOpen: (next: boolean) => void;
  triggerId: string;
  menuId: string;
  triggerRef: React.RefObject<HTMLButtonElement | null>;
  /** Bounding rect captured once when the menu opens. */
  triggerRect: Rect | null;
  setTriggerRect: (r: Rect | null) => void;
  /** Dev-only: count Trigger children so we can warn about multiples. */
  triggerCount: number;
  incTriggerCount: () => void;
  decTriggerCount: () => void;
}

const RootContext = createContext<RootCtx | null>(null);

function useRoot(componentName: string): RootCtx {
  const ctx = useContext(RootContext);
  if (!ctx) {
    throw new Error(
      `[artui] <DropdownMenu.${componentName}> must be rendered inside <DropdownMenu>.`,
    );
  }
  return ctx;
}

// ---------------------------------------------------------------------------
// Sub context
// ---------------------------------------------------------------------------

interface SubCtx {
  subOpen: boolean;
  setSubOpen: (next: boolean) => void;
  subTriggerId: string;
  subMenuId: string;
  subTriggerRect: Rect | null;
  setSubTriggerRect: (r: Rect | null) => void;
  /** Ref written synchronously by SubTrigger's effect; read by SubContent's dev guard. */
  hasSubTriggerRef: React.MutableRefObject<boolean>;
}

const SubContext = createContext<SubCtx | null>(null);

function useSub(componentName: string): SubCtx {
  const ctx = useContext(SubContext);
  if (!ctx) {
    throw new Error(
      `[artui] <DropdownMenu.${componentName}> must be rendered inside <DropdownMenu.Sub>.`,
    );
  }
  return ctx;
}

// ---------------------------------------------------------------------------
// Keyboard helpers
// ---------------------------------------------------------------------------

const FOCUSABLE_ITEM =
  '[role="menuitem"]:not([aria-disabled="true"]):not([hidden])';

function getItems(menu: HTMLElement): HTMLElement[] {
  // Scope to direct children of the menu container so that items inside a
  // nested SubContent (which is a DOM descendant) are not included in the
  // parent menu's item list. The :scope pseudo-class anchors the selector to
  // the element itself, and > limits the match to immediate children of *that*
  // element — child submenus have their own wrapper div so their menuitem
  // descendants don't match.
  return Array.from(
    menu.querySelectorAll<HTMLElement>(`:scope > ${FOCUSABLE_ITEM}`),
  );
}

function focusItem(items: HTMLElement[], index: number): void {
  items[index]?.focus();
}

// ---------------------------------------------------------------------------
// Positioning helper
// ---------------------------------------------------------------------------

function captureRect(el: HTMLElement): Rect {
  const r = el.getBoundingClientRect();
  return { top: r.top, left: r.left, width: r.width, height: r.height };
}

// ---------------------------------------------------------------------------
// Root
// ---------------------------------------------------------------------------

interface DropdownMenuRootProps {
  children: ReactNode;
  /** When provided, the menu is controlled externally. */
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

function DropdownMenuRoot({
  children,
  open: controlledOpen,
  onOpenChange,
}: DropdownMenuRootProps): ReactElement {
  const isControlled = controlledOpen !== undefined;
  const [internalOpen, setInternalOpen] = useState(false);
  const uid = useId();
  const triggerId = `${uid}-trigger`;
  const menuId = `${uid}-menu`;
  const triggerRef = useRef<HTMLButtonElement | null>(null);
  const [triggerRect, setTriggerRect] = useState<Rect | null>(null);
  const [triggerCount, setTriggerCount] = useState(0);

  const open = isControlled ? (controlledOpen ?? false) : internalOpen;

  const setOpen = useCallback(
    (next: boolean) => {
      if (!isControlled) setInternalOpen(next);
      onOpenChange?.(next);
    },
    [isControlled, onOpenChange],
  );

  const incTriggerCount = useCallback(() => {
    setTriggerCount((n) => n + 1);
  }, []);
  const decTriggerCount = useCallback(() => {
    setTriggerCount((n) => Math.max(0, n - 1));
  }, []);

  // Close on any scroll or resize — compute rect only once on open.
  useEffect(() => {
    if (!open) return;

    const close = () => setOpen(false);
    window.addEventListener("scroll", close, { passive: true, capture: true });
    window.addEventListener("resize", close, { passive: true });

    return () => {
      window.removeEventListener("scroll", close, { capture: true });
      window.removeEventListener("resize", close);
    };
  }, [open, setOpen]);

  const ctx: RootCtx = {
    open,
    setOpen,
    triggerId,
    menuId,
    triggerRef,
    triggerRect,
    setTriggerRect,
    triggerCount,
    incTriggerCount,
    decTriggerCount,
  };

  return <RootContext.Provider value={ctx}>{children}</RootContext.Provider>;
}

// ---------------------------------------------------------------------------
// Trigger
// ---------------------------------------------------------------------------

type TriggerProps = AccessibleNameProps & {
  className?: string;
  disabled?: boolean;
};

function Trigger({
  className,
  disabled,
  ...accessibleNameProps
}: TriggerProps): ReactElement {
  const {
    open,
    setOpen,
    triggerId,
    menuId,
    triggerRef,
    setTriggerRect,
    triggerCount,
    incTriggerCount,
    decTriggerCount,
  } = useRoot("Trigger");

  // Register this trigger for the multiple-triggers guard.
  // Cleanup is required so React Strict Mode's double-invoke doesn't inflate the count.
  useEffect(() => {
    incTriggerCount();
    return () => decTriggerCount();
  }, [incTriggerCount, decTriggerCount]);

  const handleClick = () => {
    if (disabled) return;
    if (!open && triggerRef.current) {
      setTriggerRect(captureRect(triggerRef.current));
    }
    setOpen(!open);
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    if (disabled) return;
    if (e.key === "ArrowDown" || e.key === "ArrowUp") {
      e.preventDefault();
      if (!open && triggerRef.current) {
        setTriggerRect(captureRect(triggerRef.current));
      }
      setOpen(true);
    }
  };

  // Spread accessible name props (children, aria-label, or aria-labelledby).
  const nameProps = accessibleNameProps as {
    children?: string;
    "aria-label"?: string;
    "aria-labelledby"?: string;
  };

  let element = (
    <button
      ref={triggerRef}
      id={triggerId}
      type="button"
      aria-haspopup="menu"
      aria-expanded={open}
      aria-controls={menuId}
      disabled={disabled}
      className={["artui-dropdown-trigger", className]
        .filter(Boolean)
        .join(" ")}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      {...(nameProps["aria-label"] !== undefined
        ? { "aria-label": nameProps["aria-label"] }
        : {})}
      {...(nameProps["aria-labelledby"] !== undefined
        ? { "aria-labelledby": nameProps["aria-labelledby"] }
        : {})}
    >
      {nameProps.children}
    </button>
  );

  if (triggerCount > 1) {
    element = withErrorOverlay(element, {
      key: "DropdownMenu:multiple-triggers",
      component: "DropdownMenu.Trigger",
      message:
        "Multiple Trigger elements detected inside one DropdownMenu. Only one Trigger is allowed per root.",
    });
  }

  return element;
}

// ---------------------------------------------------------------------------
// Content (menu panel)
// ---------------------------------------------------------------------------

interface ContentProps {
  children: ReactNode;
  className?: string;
}

function Content({ children, className }: ContentProps): ReactElement | null {
  const { open, setOpen, menuId, triggerId, triggerRect, triggerRef } = useRoot("Content");
  const menuRef = useRef<HTMLDivElement>(null);

  // Move focus to the first menu item when the menu opens.
  useEffect(() => {
    if (!open || !menuRef.current) return;
    const items = getItems(menuRef.current);
    if (items.length > 0) {
      items[0]?.focus();
    }
  }, [open]);

  // Click outside the menu closes it. Pointerdown captures the press before
  // any focus shifts so we can compare the target against the menu and trigger.
  useEffect(() => {
    if (!open) return;
    const handlePointerDown = (e: PointerEvent) => {
      const target = e.target as Node | null;
      if (!target) return;
      if (menuRef.current?.contains(target)) return;
      if (triggerRef.current?.contains(target)) return;
      setOpen(false);
    };
    document.addEventListener("pointerdown", handlePointerDown, true);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown, true);
    };
  }, [open, setOpen, triggerRef]);

  // In controlled mode the menu may open without a trigger click, so triggerRect
  // may be null. Capture it from the live button ref as a fallback.
  const resolvedRect =
    triggerRect ?? (triggerRef.current ? captureRect(triggerRef.current) : null);

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (!menuRef.current) return;
    const items = getItems(menuRef.current);
    const current = document.activeElement as HTMLElement;
    const idx = items.indexOf(current);

    switch (e.key) {
      case "ArrowDown": {
        e.preventDefault();
        focusItem(items, (idx + 1) % items.length);
        break;
      }
      case "ArrowUp": {
        e.preventDefault();
        focusItem(items, (idx - 1 + items.length) % items.length);
        break;
      }
      case "Home": {
        e.preventDefault();
        focusItem(items, 0);
        break;
      }
      case "End": {
        e.preventDefault();
        focusItem(items, items.length - 1);
        break;
      }
      case "Escape": {
        e.preventDefault();
        setOpen(false);
        triggerRef.current?.focus();
        break;
      }
      case "Tab": {
        // Tab closes the menu and lets the browser move focus naturally.
        setOpen(false);
        break;
      }
      default: {
        // Typeahead: jump to first item starting with pressed character.
        if (e.key.length === 1) {
          const ch = e.key.toLowerCase();
          const match = items.find((item) =>
            item.textContent?.trim().toLowerCase().startsWith(ch),
          );
          if (match) {
            e.preventDefault();
            match.focus();
          }
        }
      }
    }
  };

  if (!open || !resolvedRect) return null;

  const style: React.CSSProperties = {
    position: "fixed",
    top: resolvedRect.top + resolvedRect.height,
    left: resolvedRect.left,
    minWidth: resolvedRect.width,
  };

  const hasItems =
    children !== null && children !== undefined && children !== false;

  const element = (
    <div
      ref={menuRef}
      id={menuId}
      role="menu"
      aria-labelledby={triggerId}
      tabIndex={-1}
      className={["artui-dropdown-content", className].filter(Boolean).join(" ")}
      style={style}
      onKeyDown={handleKeyDown}
    >
      {children}
    </div>
  );

  if (!hasItems) {
    return withErrorOverlay(element, {
      key: "DropdownMenu:empty-content",
      component: "DropdownMenu.Content",
      wcag: "1.3.1",
      message:
        "Content rendered with no children. A menu must contain at least one item so keyboard and screen reader users can interact with it.",
    });
  }

  return element;
}

// ---------------------------------------------------------------------------
// Item
// ---------------------------------------------------------------------------

interface ItemProps {
  children: ReactNode;
  onSelect: () => void;
  disabled?: boolean;
  className?: string;
}

function Item({
  children,
  onSelect,
  disabled,
  className,
}: ItemProps): ReactElement {
  const { setOpen, triggerRef } = useRoot("Item");

  const handleClick = () => {
    if (disabled) return;
    onSelect();
    setOpen(false);
    triggerRef.current?.focus();
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      handleClick();
    }
  };

  return (
    <div
      role="menuitem"
      tabIndex={-1}
      aria-disabled={disabled ? "true" : undefined}
      className={["artui-dropdown-item", disabled && "artui-dropdown-item--disabled", className]
        .filter(Boolean)
        .join(" ")}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
    >
      {children}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Separator
// ---------------------------------------------------------------------------

interface SeparatorProps {
  className?: string;
}

function Separator({ className }: SeparatorProps): ReactElement {
  return (
    <div
      role="separator"
      aria-orientation="horizontal"
      className={["artui-dropdown-separator", className].filter(Boolean).join(" ")}
    />
  );
}

// ---------------------------------------------------------------------------
// Sub root
// ---------------------------------------------------------------------------

interface SubProps {
  children: ReactNode;
}

function Sub({ children }: SubProps): ReactElement {
  const uid = useId();
  const subTriggerId = `${uid}-sub-trigger`;
  const subMenuId = `${uid}-sub-menu`;
  const [subOpen, setSubOpen] = useState(false);
  const [subTriggerRect, setSubTriggerRect] = useState<Rect | null>(null);
  const hasSubTriggerRef = useRef(false);

  const ctx: SubCtx = {
    subOpen,
    setSubOpen,
    subTriggerId,
    subMenuId,
    subTriggerRect,
    setSubTriggerRect,
    hasSubTriggerRef,
  };

  return <SubContext.Provider value={ctx}>{children}</SubContext.Provider>;
}

// ---------------------------------------------------------------------------
// SubTrigger
// ---------------------------------------------------------------------------

type SubTriggerProps = AccessibleNameProps & {
  className?: string;
  disabled?: boolean;
};

function SubTrigger({
  className,
  disabled,
  ...accessibleNameProps
}: SubTriggerProps): ReactElement {
  const { setOpen, triggerRef: rootTriggerRef } = useRoot("SubTrigger");
  const { subOpen, setSubOpen, subTriggerId, subMenuId, setSubTriggerRect, hasSubTriggerRef } =
    useSub("SubTrigger");

  const triggerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    hasSubTriggerRef.current = true;
    return () => {
      hasSubTriggerRef.current = false;
    };
  }, [hasSubTriggerRef]);

  const openSub = () => {
    if (disabled) return;
    if (triggerRef.current) {
      setSubTriggerRect(captureRect(triggerRef.current));
    }
    setSubOpen(true);
  };

  const handleClick = () => openSub();

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (disabled) return;
    if (e.key === "ArrowRight" || e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      openSub();
    }
    if (e.key === "Escape") {
      e.preventDefault();
      setOpen(false);
      rootTriggerRef.current?.focus();
    }
  };

  const nameProps = accessibleNameProps as {
    children?: string;
    "aria-label"?: string;
    "aria-labelledby"?: string;
  };

  return (
    <div
      ref={triggerRef}
      id={subTriggerId}
      role="menuitem"
      tabIndex={-1}
      aria-haspopup="menu"
      aria-expanded={subOpen}
      aria-controls={subMenuId}
      aria-disabled={disabled ? "true" : undefined}
      className={[
        "artui-dropdown-item",
        "artui-dropdown-subtrigger",
        disabled && "artui-dropdown-item--disabled",
        className,
      ]
        .filter(Boolean)
        .join(" ")}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      {...(nameProps["aria-label"] !== undefined
        ? { "aria-label": nameProps["aria-label"] }
        : {})}
      {...(nameProps["aria-labelledby"] !== undefined
        ? { "aria-labelledby": nameProps["aria-labelledby"] }
        : {})}
    >
      {nameProps.children}
      <span aria-hidden="true" className="artui-dropdown-subtrigger-arrow">
        &rsaquo;
      </span>
    </div>
  );
}

// ---------------------------------------------------------------------------
// SubContent (portals as fixed overlay, sibling to body)
// ---------------------------------------------------------------------------

interface SubContentProps {
  children: ReactNode;
  className?: string;
}

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

function SubContent({ children, className }: SubContentProps): ReactElement | null {
  const { setOpen } = useRoot("SubContent");
  const { subOpen, setSubOpen, subMenuId, subTriggerId, subTriggerRect, hasSubTriggerRef } =
    useSub("SubContent");

  const menuRef = useRef<HTMLDivElement>(null);

  // Dev guard: fire if SubContent has no matching SubTrigger inside the same Sub.
  // SubTrigger writes hasSubTriggerRef.current synchronously in its effect commit,
  // before any setTimeout fires, so no re-render race is possible.
  useEffect(() => {
    if (!isDev) return;
    const id = setTimeout(() => {
      if (!hasSubTriggerRef.current) {
        console.error(
          "[artui] <DropdownMenu.SubContent>: subtrigger-without-subcontent — " +
            "SubContent rendered without a matching SubTrigger inside the same Sub. " +
            "Every Sub must contain exactly one SubTrigger and one SubContent.",
        );
      }
    }, 0);
    return () => clearTimeout(id);
  }, [hasSubTriggerRef]);

  useEffect(() => {
    if (!subOpen || !menuRef.current) return;
    const items = getItems(menuRef.current);
    if (items.length > 0) items[0]?.focus();
  }, [subOpen]);

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (!menuRef.current) return;
    const items = getItems(menuRef.current);
    const current = document.activeElement as HTMLElement;
    const idx = items.indexOf(current);

    switch (e.key) {
      case "ArrowDown": {
        e.preventDefault();
        // Stop propagation so the parent Content's ArrowDown handler does not
        // also fire and override the focus move inside this submenu.
        e.stopPropagation();
        focusItem(items, (idx + 1) % items.length);
        break;
      }
      case "ArrowUp": {
        e.preventDefault();
        e.stopPropagation();
        focusItem(items, (idx - 1 + items.length) % items.length);
        break;
      }
      case "Home": {
        e.preventDefault();
        e.stopPropagation();
        focusItem(items, 0);
        break;
      }
      case "End": {
        e.preventDefault();
        e.stopPropagation();
        focusItem(items, items.length - 1);
        break;
      }
      case "ArrowLeft":
      case "Escape": {
        e.preventDefault();
        // Stop propagation so the root Content's Escape handler does not also fire.
        e.stopPropagation();
        setSubOpen(false);
        // Return focus to the sub-trigger in the parent menu.
        document.getElementById(subTriggerId)?.focus();
        break;
      }
      case "Tab": {
        // Stop propagation — Tab already closes everything; parent handler
        // must not also run and attempt to move focus a second time.
        e.stopPropagation();
        setSubOpen(false);
        setOpen(false);
        break;
      }
      default: {
        if (e.key.length === 1) {
          const ch = e.key.toLowerCase();
          const match = items.find((item) =>
            item.textContent?.trim().toLowerCase().startsWith(ch),
          );
          if (match) {
            e.preventDefault();
            e.stopPropagation();
            match.focus();
          }
        }
      }
    }
  };

  if (!subOpen || !subTriggerRect) return null;

  // Read offsets from CSS tokens so consumers can theme without touching JS.
  // Horizontal: small gap so the submenu's border/shadow doesn't collide with
  // the parent menu's right edge. Vertical: pull up by the panel's own top
  // padding so the first item aligns with the sub-trigger row.
  const rootStyles =
    typeof window !== "undefined"
      ? getComputedStyle(document.documentElement)
      : null;
  const subOffset =
    parseFloat(rootStyles?.getPropertyValue("--artui-dropdown-sub-offset") ?? "") || 4;
  const contentPadding =
    parseFloat(rootStyles?.getPropertyValue("--artui-dropdown-content-padding") ?? "") || 4;

  const style: React.CSSProperties = {
    position: "fixed",
    top: subTriggerRect.top - contentPadding,
    // Render to the right of the sub-trigger, with a small gap.
    left: subTriggerRect.left + subTriggerRect.width + subOffset,
  };

  let element = (
    <div
      ref={menuRef}
      id={subMenuId}
      role="menu"
      aria-labelledby={subTriggerId}
      tabIndex={-1}
      className={["artui-dropdown-content", className].filter(Boolean).join(" ")}
      style={style}
      onKeyDown={handleKeyDown}
    >
      {children}
    </div>
  );

  if (!hasSubTriggerRef.current) {
    element = withErrorOverlay(element, {
      key: "DropdownMenu:subtrigger-without-subcontent",
      component: "DropdownMenu.SubContent",
      message:
        "SubContent rendered without a matching SubTrigger inside the same Sub. Every Sub must contain exactly one SubTrigger and one SubContent.",
    });
  }

  return element;
}

// ---------------------------------------------------------------------------
// Namespace export
// ---------------------------------------------------------------------------

/**
 * Accessible dropdown menu following the WAI-ARIA APG Menu Button pattern.
 *
 * @example
 * <DropdownMenu>
 *   <DropdownMenu.Trigger>Account</DropdownMenu.Trigger>
 *   <DropdownMenu.Content>
 *     <DropdownMenu.Item onSelect={goToProfile}>Profile</DropdownMenu.Item>
 *     <DropdownMenu.Separator />
 *     <DropdownMenu.Sub>
 *       <DropdownMenu.SubTrigger>Preferences</DropdownMenu.SubTrigger>
 *       <DropdownMenu.SubContent>
 *         <DropdownMenu.Item onSelect={setLight}>Light theme</DropdownMenu.Item>
 *       </DropdownMenu.SubContent>
 *     </DropdownMenu.Sub>
 *   </DropdownMenu.Content>
 * </DropdownMenu>
 */
export const DropdownMenu = Object.assign(DropdownMenuRoot, {
  Trigger,
  Content,
  Item,
  Separator,
  Sub,
  SubTrigger,
  SubContent,
});

:root {
  --artui-dropdown-bg: Canvas;
  --artui-dropdown-color: CanvasText;
  --artui-dropdown-shadow: 0 8px 24px rgba(0, 0, 0, 0.18);
  --artui-dropdown-border: 1px solid color-mix(in srgb, currentColor 15%, transparent);
  --artui-dropdown-radius: 8px;
  --artui-dropdown-item-radius: 4px;
  --artui-dropdown-item-padding: 8px 12px;
  --artui-dropdown-content-padding: 4px;
  /* Horizontal breathing room between a parent menu and its submenu so the
     borders and box-shadows don't visually collide at the seam. */
  --artui-dropdown-sub-offset: 4px;
  --artui-dropdown-focus-outline: 2px solid currentColor;
  --artui-dropdown-focus-outline-offset: -2px;
  --artui-dropdown-item-hover-bg: color-mix(in srgb, currentColor 8%, transparent);
  --artui-dropdown-item-disabled-opacity: 0.45;
  --artui-dropdown-separator-color: color-mix(in srgb, currentColor 15%, transparent);
  --artui-dropdown-z-index: 9000;
}

/* ---- Trigger ---- */

.artui-dropdown-trigger {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  min-inline-size: 44px;
  min-block-size: 44px;
  padding: 8px 14px;
  background: transparent;
  color: inherit;
  border: var(--artui-dropdown-border);
  border-radius: var(--artui-dropdown-radius);
  cursor: pointer;
  font: inherit;

  &:focus {
    outline: var(--artui-dropdown-focus-outline);
    outline-offset: var(--artui-dropdown-focus-outline-offset);
  }

  &:hover:not(:disabled) {
    background: var(--artui-dropdown-item-hover-bg);
  }

  &:disabled {
    opacity: var(--artui-dropdown-item-disabled-opacity);
    cursor: not-allowed;
  }
}

/* ---- Content panel (both root and sub) ---- */

.artui-dropdown-content {
  z-index: var(--artui-dropdown-z-index);
  min-width: 160px;
  padding: var(--artui-dropdown-content-padding);
  background: var(--artui-dropdown-bg);
  color: var(--artui-dropdown-color);
  border: var(--artui-dropdown-border);
  border-radius: var(--artui-dropdown-radius);
  box-shadow: var(--artui-dropdown-shadow);
  font-family: inherit;
  font-size: inherit;

  &:focus {
    outline: none;
  }
}

/* ---- Item ---- */

.artui-dropdown-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: var(--artui-dropdown-item-padding);
  border-radius: var(--artui-dropdown-item-radius);
  cursor: pointer;
  user-select: none;

  &:focus {
    outline: var(--artui-dropdown-focus-outline);
    outline-offset: var(--artui-dropdown-focus-outline-offset);
    background: var(--artui-dropdown-item-hover-bg);
  }

  &:hover:not(.artui-dropdown-item--disabled) {
    background: var(--artui-dropdown-item-hover-bg);
  }

  &.artui-dropdown-item--disabled {
    opacity: var(--artui-dropdown-item-disabled-opacity);
    cursor: not-allowed;
    pointer-events: none;
  }
}

/* ---- SubTrigger arrow ---- */

.artui-dropdown-subtrigger {
  justify-content: space-between;
}

.artui-dropdown-subtrigger-arrow {
  font-size: 1.1em;
  line-height: 1;
  opacity: 0.6;
}

/* ---- Separator ---- */

.artui-dropdown-separator {
  height: 1px;
  margin: 4px 0;
  background: var(--artui-dropdown-separator-color);
}

/* ---- Entrance animation (respects prefers-reduced-motion) ---- */

@media (prefers-reduced-motion: no-preference) {
  .artui-dropdown-content {
    animation: artui-dropdown-in 130ms ease-out;
  }
}

@keyframes artui-dropdown-in {
  from {
    opacity: 0;
    transform: translateY(-4px) scale(0.98);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

import type { ReactElement } from "react";

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

const reported = new Set<string>();

interface DevOverlayOptions {
  /** Stable key for de-duplicating the console.error call. */
  key: string;
  /** Component name shown in the error prefix, e.g. "Image". */
  component: string;
  /** Optional WCAG criterion, e.g. "1.1.1". */
  wcag?: string;
  /** Human-readable description of what went wrong. */
  message: string;
}

/**
 * Wraps `element` in a red full-coverage overlay and emits a console.error.
 *
 * No-op in production. In development, logs once per `key` then returns the
 * element wrapped in a positioned <span> with a red overlay on top.
 * The overlay uses aria-hidden and pointerEvents:none so it does not affect
 * the accessibility tree or interaction.
 */
export function withErrorOverlay(
  element: ReactElement,
  { key, component, wcag, message }: DevOverlayOptions,
): ReactElement {
  if (!isDev) return element;

  if (!reported.has(key)) {
    reported.add(key);
    const wcagSuffix = wcag ? ` [WCAG ${wcag}]` : "";
    console.error(`[artui] <${component}>${wcagSuffix}: ${message}`);
  }

  return (
    <span style={{ position: "relative", display: "inline-block" }}>
      {element}
      <span
        aria-hidden="true"
        style={{
          position: "absolute",
          inset: 0,
          background: "#d62828",
          pointerEvents: "none",
        }}
      />
    </span>
  );
}

/** Reset the de-duplication cache. Test-only. */
export function __resetDevOverlayCache(): void {
  reported.clear();
}

import { type ImgHTMLAttributes, useMemo } from 'react';

import { withErrorOverlay } from '../../lib/dev-overlay';

// ---------------------------------------------------------------------------
// Module constants
// ---------------------------------------------------------------------------

const FORBIDDEN_ALTS = ['', 'img', 'image', 'photo', 'picture', 'icon'] as const;
type ForbiddenAlt = (typeof FORBIDDEN_ALTS)[number];

// ---------------------------------------------------------------------------
// Props — discriminated union: meaningful alt OR explicit decorative flag
// ---------------------------------------------------------------------------

type SafeAlt<T extends string> =
  Lowercase<T> extends ForbiddenAlt
    ? `'${T}' is not meaningful alt text. Describe what the image shows`
    : T;

type BaseImgProps = Omit<ImgHTMLAttributes<HTMLImageElement>, 'alt' | 'role'>;

type DecorativeProps = BaseImgProps & {
  decorative: true;
  alt?: never;
};

type AccessibleProps<T extends string> = BaseImgProps & {
  decorative?: false;
  alt: SafeAlt<T>;
};

export type ImageProps<T extends string> = DecorativeProps | AccessibleProps<T>;

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function Image<const T extends string>(props: ImageProps<T>) {
  // Props
  const { decorative, alt, style, loading, ...rest } = props as
    | (DecorativeProps & { alt?: undefined })
    | (AccessibleProps<string> & { decorative?: false });

  // Computed
  const runtimeError = useMemo(() => {
    if (decorative) return null;
    const value = typeof alt === 'string' ? alt.trim() : '';
    if (value === '') {
      return 'Alt text is empty or contains only whitespace.';
    }
    if ((FORBIDDEN_ALTS as readonly string[]).includes(value.toLowerCase())) {
      return `'${alt}' is not meaningful alt text. Describe what the image shows.`;
    }
    return null;
  }, [decorative, alt]);

  // Render
  if (decorative) {
    return <img {...rest} alt="" role="presentation" loading={loading ?? 'lazy'} style={style} />;
  }

  const img = <img {...rest} alt={alt as string} loading={loading ?? 'lazy'} style={style} />;

  if (!runtimeError) return img;

  return withErrorOverlay(img, {
    key: `Image:placeholder-alt:${String(alt)}`,
    component: 'Image',
    wcag: '1.1.1',
    message: runtimeError,
  });
}

import type { ReactElement } from "react";

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

const reported = new Set<string>();

interface DevOverlayOptions {
  /** Stable key for de-duplicating the console.error call. */
  key: string;
  /** Component name shown in the error prefix, e.g. "Image". */
  component: string;
  /** Optional WCAG criterion, e.g. "1.1.1". */
  wcag?: string;
  /** Human-readable description of what went wrong. */
  message: string;
}

/**
 * Wraps `element` in a red full-coverage overlay and emits a console.error.
 *
 * No-op in production. In development, logs once per `key` then returns the
 * element wrapped in a positioned <span> with a red overlay on top.
 * The overlay uses aria-hidden and pointerEvents:none so it does not affect
 * the accessibility tree or interaction.
 */
export function withErrorOverlay(
  element: ReactElement,
  { key, component, wcag, message }: DevOverlayOptions,
): ReactElement {
  if (!isDev) return element;

  if (!reported.has(key)) {
    reported.add(key);
    const wcagSuffix = wcag ? ` [WCAG ${wcag}]` : "";
    console.error(`[artui] <${component}>${wcagSuffix}: ${message}`);
  }

  return (
    <span style={{ position: "relative", display: "inline-block" }}>
      {element}
      <span
        aria-hidden="true"
        style={{
          position: "absolute",
          inset: 0,
          background: "#d62828",
          pointerEvents: "none",
        }}
      />
    </span>
  );
}

/** Reset the de-duplication cache. Test-only. */
export function __resetDevOverlayCache(): void {
  reported.clear();
}
